const token = $input.first().json.headers['x-admin-token'];
if (!token) return [{json: {ok: 'false', error: 'No autorizado'}}];
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  const parts = decoded.split('|');
  if (parts.length !== 3 || parts[2] !== 'CrackTesos2026_Admin_Token') {
    return [{json: {ok: 'false', error: 'Token inválido'}}];
  }
  const tokenAge = Date.now() - parseInt(parts[1]);
  if (tokenAge > 8 * 3600 * 1000) return [{json: {ok: 'false', error: 'Sesión expirada'}}];
} catch(e) {
  return [{json: {ok: 'false', error: 'Token inválido'}}];
}
const body = $input.first().json.body;
if (!body.trivia_id || !body.trivia_number || !body.eligible_users?.length) {
  return [{json: {ok: 'false', error: 'Datos incompletos'}}];
}
return [{json: {
  ok: 'true',
  trivia_id: body.trivia_id,
  trivia_number: body.trivia_number,
  eligible_users: body.eligible_users,
  operator_email: body.operator_email || 'unknown',
  source_file: body.source_file || 'upload'
}}];

const validated = $('Validar').first().json;

const batchId = crypto.randomUUID();

const users = validated.eligible_users.filter(u => !u.already_applied && u.multiplier > 0);

if (users.length === 0) {
  throw new Error('Todos los usuarios ya tienen el multiplicador aplicado');
}

const totalGoalsAdded = users.reduce((s, u) => s + u.goals_to_add, 0);

// Valores de la tabla temporal con los datos por usuario
const userValues = users.map(u =>
  `('${u.user_id}'::uuid, ${u.goals_to_add}, '${u.response_id}'::uuid, ${u.goals_final})`
).join(',\n    ');

// Valores del ledger
const ledgerValues = users.map(u =>
  `('${u.user_id}'::uuid, '${validated.trivia_id}'::uuid, ${validated.trivia_number}, 'multiplier_bonus', ${u.goals_to_add}, '+${u.goals_to_add} goles por ${u.number_of_codes} códigos — Trivia #${validated.trivia_number}', '${batchId}'::uuid, 'admin:${validated.operator_email}')`
).join(',\n    ');

// Una sola consulta CTE atómica que retorna 1 fila
const fullSql = `
WITH
user_data(user_id, goals_to_add, response_id, final_goals) AS (
  VALUES ${userValues}
),
batch_ins AS (
  INSERT INTO ct_multiplier_batches (batch_id, trivia_id, trivia_number, source_file, total_records_file, eligible_records, applied_records, total_goals_added, status, applied_at, applied_by, ip_address)
  VALUES ('${batchId}', '${validated.trivia_id}', ${validated.trivia_number}, '${validated.source_file}', ${users.length}, ${users.length}, ${users.length}, ${totalGoalsAdded}, 'applied', NOW() AT TIME ZONE 'America/Bogota', '${validated.operator_email}', 'web-module')
  RETURNING batch_id
),
ledger_ins AS (
  INSERT INTO ct_scoring_ledger (user_id, trivia_id, trivia_number, movement_type, amount, description, reference_id, created_by)
  VALUES ${ledgerValues}
  RETURNING ledger_id
),
resp_upd AS (
  UPDATE ct_trivia_responses tr
  SET multiplier_bonus = ud.goals_to_add, final_goals = ud.final_goals
  FROM user_data ud
  WHERE tr.response_id = ud.response_id
  RETURNING tr.response_id
),
user_upd AS (
  UPDATE ct_users cu
  SET total_goals = cu.total_goals + ud.goals_to_add, updated_at = NOW()
  FROM user_data ud
  WHERE cu.user_id = ud.user_id
  RETURNING cu.user_id
)
INSERT INTO ct_audit_logs (event_type, operator_email, trivia_number, user_affected, payload, result, ip_address)
VALUES ('multiplier_applied', '${validated.operator_email}', ${validated.trivia_number}, 'bulk:${users.length}', '{"batch_id": "${batchId}", "total_goals_added": ${totalGoalsAdded}}'::jsonb, 'success', 'web-module')
RETURNING log_id;
`;

return [{json: {
  ok: 'true',
  batch_id: batchId,
  trivia_id: validated.trivia_id,
  trivia_number: validated.trivia_number,
  operator_email: validated.operator_email,
  users_count: users.length,
  total_goals_added: totalGoalsAdded,
  fullSql
}}];
